public class StripeAdapter implements PaymentProcessor { private final StripeGateway gateway = new StripeGateway(); public boolean processPayment(String orderId, double amount) { long cents = (long)(amount * 100); String id = gateway.charge(orderId, cents); return id != null; } public boolean refund(String transactionId) { return gateway.reverse(transactionId); } public String getGatewayName() { return "Stripe"; } }